import { useLiveQuery } from 'dexie-react-hooks';
import { db } from '../lib/db';
import { Link } from 'react-router-dom';
import { Brain, Trash2, TrendingDown } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

export default function Mistakes() {
  // Get words with mistakes, sorted by mistake count descending
  const mistakes = useLiveQuery(() => 
    db.words.where('mistakeCount').above(0).reverse().sortBy('mistakeCount')
  );

  const handleClearMistake = async (id: string, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    await db.words.update(id, { mistakeCount: 0 });
  };

  const handleClearAll = async () => {
    if (confirm('确定要清空所有错题记录吗？')) {
      const words = await db.words.where('mistakeCount').above(0).toArray();
      await Promise.all(words.map(w => db.words.update(w.id, { mistakeCount: 0 })));
    }
  };

  if (!mistakes) return <div className="text-center py-20 text-slate-400">加载中...</div>;

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <header className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-100 flex items-center gap-2">
            <span className="bg-rose-500/20 text-rose-400 p-2 rounded-lg"><Brain size={24} /></span>
            错题本
          </h1>
          <p className="text-slate-400 text-sm mt-2">共 {mistakes.length} 个易错词，集中攻克它们！</p>
        </div>

        {mistakes.length > 0 && (
          <div className="flex gap-2">
            <button 
              onClick={handleClearAll}
              className="px-4 py-2 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-xl transition-colors border border-slate-700"
            >
              清空记录
            </button>
            <Link 
              to="/study/mistakes"
              className="flex items-center gap-2 px-6 py-2 bg-rose-600 hover:bg-rose-500 text-white rounded-xl transition-colors shadow-lg shadow-rose-500/20 font-medium"
            >
              <Brain size={18} /> 开始特训
            </Link>
          </div>
        )}
      </header>

      {mistakes.length === 0 ? (
        <div className="py-20 text-center text-slate-500 bg-slate-900/50 rounded-2xl border border-dashed border-slate-700">
          <TrendingDown size={48} className="mx-auto mb-4 opacity-50 text-emerald-500" />
          <p className="text-lg text-slate-300 mb-2">太棒了！</p>
          <p>你目前没有错题记录，继续保持！</p>
        </div>
      ) : (
        <div className="grid gap-3">
          <AnimatePresence>
            {mistakes.map(word => (
              <motion.div 
                key={word.id}
                layout
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, scale: 0.9 }}
                className="bg-slate-900/80 border border-slate-800 hover:border-rose-500/30 rounded-2xl p-4 flex items-center justify-between group transition-colors"
              >
                <div className="flex-1 grid grid-cols-2 md:grid-cols-3 gap-4 items-center">
                  <div className="font-medium text-slate-200 text-lg">{word.english}</div>
                  <div className="text-slate-400">{word.chinese}</div>
                  <div className="hidden md:flex items-center gap-2">
                    <div className="bg-rose-500/10 text-rose-400 px-3 py-1 rounded-full text-sm font-mono flex items-center gap-1">
                      错误 <span className="font-bold">{word.mistakeCount}</span> 次
                    </div>
                  </div>
                </div>

                <div className="flex items-center gap-3">
                  <div className="md:hidden bg-rose-500/10 text-rose-400 px-2 py-0.5 rounded text-xs font-mono">
                    错 {word.mistakeCount}
                  </div>
                  <button 
                    onClick={(e) => handleClearMistake(word.id, e)}
                    className="p-2 text-slate-500 hover:text-emerald-400 hover:bg-emerald-500/10 rounded-lg transition-colors opacity-0 group-hover:opacity-100"
                    title="已掌握，移出错题本"
                  >
                    <Trash2 size={18} />
                  </button>
                </div>
              </motion.div>
            ))}
          </AnimatePresence>
        </div>
      )}
    </div>
  );
}
