import { useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { useLiveQuery } from 'dexie-react-hooks';
import { db, type Word } from '../lib/db';
import { generateId } from '../utils/cn';
import Papa from 'papaparse';
import * as mammoth from 'mammoth';
import { PlayCircle, Brain, Upload, Trash2, Edit2, ChevronLeft, Save, X, Folder } from 'lucide-react';

type ImportMode = 'text' | 'file';
type ParsedPair = { english: string; chinese: string };

function parsePairsFromLooseText(input: string): ParsedPair[] {
  // Add support for the new docx format pattern: "1. grant (264次) 授予；补助金 v./n."
  // And it allows words with spaces like "put off"
  const docxPattern = /^\d+\.\s+([a-zA-Z\-\s]+?)\s*(?:\([^)]+\))?\s+(.+)$/;

  return input
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean)
    .map((line) => {
      // 1. Try to match the docx format pattern
      const docxMatch = line.match(docxPattern);
      if (docxMatch) {
        return { english: docxMatch[1].trim(), chinese: docxMatch[2].trim() };
      }

      // 2. Try comma or tab separation
      const parts = line.split(/,|\t/).map((p) => p.trim()).filter(Boolean);
      if (parts.length >= 2) return { english: parts[0], chinese: parts.slice(1).join(' ') };

      // 3. Try space separation
      const spaceParts = line.split(/\s+/).map((p) => p.trim()).filter(Boolean);
      if (spaceParts.length >= 2) return { english: spaceParts[0], chinese: spaceParts.slice(1).join(' ') };

      return null;
    })
    .filter((x): x is ParsedPair => Boolean(x && x.english && x.chinese));
}

function parsePairsFromCsvText(input: string): ParsedPair[] {
  const withHeader = Papa.parse<Record<string, string>>(input, { header: true, skipEmptyLines: true });
  const fromHeader = withHeader.data
    .map((row) => {
      const english = (row.english ?? row.English ?? row['英文'] ?? '').trim();
      const chinese = (row.chinese ?? row.Chinese ?? row['中文'] ?? '').trim();
      if (!english || !chinese) return null;
      return { english, chinese };
    })
    .filter((x): x is ParsedPair => Boolean(x));
  if (fromHeader.length > 0) return fromHeader;

  const withoutHeader = Papa.parse<unknown[]>(input, { header: false, skipEmptyLines: true });
  return withoutHeader.data
    .map((row) => {
      if (!Array.isArray(row)) return null;
      const english = String(row[0] ?? '').trim();
      const chinese = String(row[1] ?? '').trim();
      if (!english || !chinese) return null;
      return { english, chinese };
    })
    .filter((x): x is ParsedPair => Boolean(x));
}

export default function FolderDetail() {
  const { folderId } = useParams<{ folderId: string }>();
  const navigate = useNavigate();
  
  const folder = useLiveQuery(() => folderId ? db.folders.get(folderId) : undefined, [folderId]);
  const words = useLiveQuery(
    () => folderId ? db.words.where('folderId').equals(folderId).reverse().sortBy('createdAt') : [], 
    [folderId]
  );
  
  const [importText, setImportText] = useState('');
  const [showImport, setShowImport] = useState(false);
  const [importMode, setImportMode] = useState<ImportMode>('text');
  const [importFile, setImportFile] = useState<File | null>(null);
  const [importError, setImportError] = useState<string | null>(null);
  const [isImporting, setIsImporting] = useState(false);
  const [showBatchEdit, setShowBatchEdit] = useState(false);
  const [batchEditText, setBatchEditText] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState({ english: '', chinese: '' });

  const downloadTemplate = () => {
    const content = `\ufeffenglish,chinese\napple,苹果\nbanana,香蕉\n`;
    const blob = new Blob([content], { type: 'text/csv;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `words-template.csv`;
    document.body.appendChild(a);
    a.click();
    a.remove();
    URL.revokeObjectURL(url);
  };

  const commitPairsToDb = async (pairs: ParsedPair[]) => {
    if (!folderId) return;
    const now = Date.now();
    const newWords: Word[] = pairs.map((p, index) => ({
      id: generateId(),
      folderId,
      english: p.english,
      chinese: p.chinese,
      mistakeCount: 0,
      lastPracticed: now,
      createdAt: now + index, // Ensure slightly different timestamps to maintain order
    }));
    await db.words.bulkAdd(newWords);
  };

  const handleImport = async () => {
    if (!folderId) return;
    setImportError(null);
    setIsImporting(true);
    try {
      let pairs: ParsedPair[] = [];
      if (importMode === 'text') {
        if (!importText.trim()) return;
        const fromCsv = parsePairsFromCsvText(importText);
        pairs = fromCsv.length > 0 ? fromCsv : parsePairsFromLooseText(importText);
      } else {
        if (!importFile) return;
        
        let text = '';
        const isDocx = /\.docx$/i.test(importFile.name);
        
        if (isDocx) {
          const arrayBuffer = await importFile.arrayBuffer();
          const result = await mammoth.extractRawText({ arrayBuffer });
          text = result.value;
        } else {
          text = await importFile.text();
        }

        const isCsv = /\.csv$/i.test(importFile.name);
        pairs = isCsv ? parsePairsFromCsvText(text) : parsePairsFromLooseText(text);
      }

      if (pairs.length === 0) {
        setImportError('未解析到可用数据。请使用模板（english,chinese）或 “apple,苹果 / apple 苹果” 这种格式。');
        return;
      }

      await commitPairsToDb(pairs);
      setImportText('');
      setImportFile(null);
      setShowImport(false);
    } finally {
      setIsImporting(false);
    }
  };

  const startBatchEdit = () => {
    if (!words) return;
    const text = words.map(w => `${w.english}, ${w.chinese}`).join('\n');
    setBatchEditText(text);
    setShowBatchEdit(true);
    setShowImport(false);
  };

  const saveBatchEdit = async () => {
    if (!batchEditText.trim() || !folderId || !words) return;

    const fromCsv = parsePairsFromCsvText(batchEditText);
    const parsedPairs = fromCsv.length > 0 ? fromCsv : parsePairsFromLooseText(batchEditText);

    if (parsedPairs.length > 0) {
      if (confirm(`即将用这 ${parsedPairs.length} 个单词覆盖当前文件夹的 ${words.length} 个单词，原有的错题记录将重置，确定继续吗？`)) {
        await db.words.where('folderId').equals(folderId).delete();
        await commitPairsToDb(parsedPairs);
        setShowBatchEdit(false);
      }
    } else {
      alert('无法解析输入的单词。');
    }
  };

  const handleDelete = async (id: string) => {
    await db.words.delete(id);
  };

  const startEdit = (word: Word) => {
    setEditingId(word.id);
    setEditForm({ english: word.english, chinese: word.chinese });
  };

  const saveEdit = async () => {
    if (editingId) {
      await db.words.update(editingId, { ...editForm });
      setEditingId(null);
    }
  };

  if (!folder) return <div className="text-center py-20 text-slate-400">加载中...</div>;

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Header */}
      <header className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4">
        <div>
          <button onClick={() => navigate('/library')} className="flex items-center text-slate-400 hover:text-white mb-2 text-sm transition-colors">
            <ChevronLeft size={16} /> 返回词库
          </button>
          <h1 className="text-2xl font-bold text-slate-100 flex items-center gap-2">
            <span className="bg-blue-500/20 text-blue-400 p-2 rounded-lg"><Folder size={24} /></span>
            {folder.name}
          </h1>
          <p className="text-slate-400 text-sm mt-2">共有 {words?.length || 0} 个单词</p>
        </div>

        {/* Action Buttons */}
        <div className="flex flex-wrap gap-2">
          <Link
            to={`/study/match/${folderId}`}
            className="flex-1 sm:flex-none flex justify-center items-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2 rounded-xl transition-colors font-medium shadow-lg shadow-indigo-500/20"
          >
            <PlayCircle size={18} /> 连连看
          </Link>
          <Link
            to={`/study/dictation/${folderId}`}
            className="flex-1 sm:flex-none flex justify-center items-center gap-2 bg-emerald-600 hover:bg-emerald-500 text-white px-4 py-2 rounded-xl transition-colors font-medium shadow-lg shadow-emerald-500/20"
          >
            <Brain size={18} /> 沉浸默写
          </Link>
          <button
            onClick={() => {
              const next = !showImport;
              setShowImport(next);
              setShowBatchEdit(false);
              setImportError(null);
              if (next) {
                setImportMode('text');
              }
            }}
            className="flex-1 sm:flex-none flex justify-center items-center gap-2 bg-slate-800 hover:bg-slate-700 text-white px-4 py-2 rounded-xl transition-colors border border-slate-700"
          >
            <Upload size={18} /> 导入
          </button>
          <button
            onClick={startBatchEdit}
            className="flex-1 sm:flex-none flex justify-center items-center gap-2 bg-slate-800 hover:bg-slate-700 text-white px-4 py-2 rounded-xl transition-colors border border-slate-700"
          >
            <Edit2 size={18} /> 批量修改
          </button>
        </div>
      </header>

      {/* Batch Edit Section */}
      {showBatchEdit && (
        <div className="bg-slate-900 border border-slate-700 rounded-2xl p-4 animate-in slide-in-from-top-4">
          <h3 className="text-sm font-medium text-slate-300 mb-2">批量修改单词</h3>
          <p className="text-xs text-slate-500 mb-4">修改文本后保存，注意此操作将覆盖当前文件夹中的所有单词并重置错题记录。</p>
          <textarea
            value={batchEditText}
            onChange={(e) => setBatchEditText(e.target.value)}
            rows={10}
            className="w-full bg-slate-950 border border-slate-800 rounded-xl p-3 text-sm text-slate-200 focus:outline-none focus:border-blue-500 transition-colors font-mono"
            placeholder="apple, 苹果&#10;banana, 香蕉"
          />
          <div className="flex justify-end mt-3 gap-2">
            <button onClick={() => setShowBatchEdit(false)} className="px-4 py-2 rounded-lg text-sm text-slate-400 hover:text-white transition-colors">取消</button>
            <button onClick={saveBatchEdit} className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-lg text-sm transition-colors">保存修改</button>
          </div>
        </div>
      )}

      {/* Import Section */}
      {showImport && (
        <div className="bg-slate-900 border border-slate-700 rounded-2xl p-4 animate-in slide-in-from-top-4">
          <div className="flex items-center justify-between gap-3 mb-4">
            <div>
              <h3 className="text-sm font-medium text-slate-200">导入单词</h3>
              <p className="text-xs text-slate-500 mt-1">支持模板 CSV（english,chinese）/ 粘贴 / 上传文件（含.docx）</p>
            </div>
            <button
              type="button"
              onClick={downloadTemplate}
              className="shrink-0 px-3 py-2 rounded-lg text-xs font-medium bg-slate-800 hover:bg-slate-700 border border-slate-700 text-slate-200 transition-colors"
            >
              下载模板
            </button>
          </div>

          <div className="grid grid-cols-2 gap-2 mb-4">
            <button
              type="button"
              onClick={() => {
                setImportMode('text');
                setImportError(null);
              }}
              className={`px-3 py-2 rounded-xl text-sm border transition-colors ${importMode === 'text' ? 'bg-blue-600/20 border-blue-500 text-blue-200' : 'bg-slate-950 border-slate-800 text-slate-300 hover:border-slate-700'}`}
            >
              粘贴导入
            </button>
            <button
              type="button"
              onClick={() => {
                setImportMode('file');
                setImportError(null);
              }}
              className={`px-3 py-2 rounded-xl text-sm border transition-colors ${importMode === 'file' ? 'bg-blue-600/20 border-blue-500 text-blue-200' : 'bg-slate-950 border-slate-800 text-slate-300 hover:border-slate-700'}`}
            >
              上传文件
            </button>
          </div>

          {importMode === 'text' ? (
            <div className="space-y-3">
              <textarea
                value={importText}
                onChange={(e) => setImportText(e.target.value)}
                rows={6}
                className="w-full bg-slate-950 border border-slate-800 rounded-xl p-3 text-sm text-slate-200 focus:outline-none focus:border-blue-500 transition-colors"
                placeholder="english,chinese&#10;apple,苹果&#10;banana,香蕉&#10;&#10;或：apple, 苹果&#10;或：apple 苹果"
              />
              <div className="text-[11px] text-slate-500 leading-relaxed">
                - 支持一行一个单词：apple,苹果 / apple 苹果<br />
                - 也支持模板 CSV：第一行 english,chinese
              </div>
            </div>
          ) : (
            <div className="space-y-3">
              <label className="block">
                <div className="w-full rounded-xl border border-slate-800 bg-slate-950 px-4 py-3 text-sm text-slate-300 hover:border-slate-700 transition-colors cursor-pointer">
                  <div className="flex items-center justify-between gap-3">
                    <span className="truncate">
                      {importFile ? importFile.name : '选择文件（.csv / .txt / .docx）'}
                    </span>
                    <span className="text-xs text-slate-500">{importFile ? `${Math.ceil(importFile.size / 1024)} KB` : ''}</span>
                  </div>
                </div>
                <input
                  type="file"
                  accept=".csv,.txt,text/plain,text/csv,.docx,application/vnd.openxmlformats-officedocument.wordprocessingml.document"
                  className="hidden"
                  onChange={(e) => {
                    setImportError(null);
                    setImportFile(e.target.files?.[0] ?? null);
                  }}
                />
              </label>
              <div className="text-[11px] text-slate-500 leading-relaxed">
                - CSV 推荐使用模板列名：english,chinese<br />
                - TXT 每行一个单词：apple,苹果 或 apple 苹果<br />
                - Docx 支持提取图片中展示的格式：1. grant (264次) 授予；补助金 v./n.
              </div>
            </div>
          )}

          {importError && (
            <div className="mt-4 rounded-xl border border-rose-500/30 bg-rose-500/10 px-4 py-3 text-sm text-rose-200">
              {importError}
            </div>
          )}

          <div className="flex justify-end mt-4 gap-2">
            <button
              type="button"
              onClick={() => setShowImport(false)}
              className="px-4 py-2 rounded-lg text-sm text-slate-400 hover:text-white transition-colors"
              disabled={isImporting}
            >
              取消
            </button>
            <button
              type="button"
              onClick={handleImport}
              disabled={isImporting || (importMode === 'text' ? !importText.trim() : !importFile)}
              className="bg-blue-600 hover:bg-blue-500 disabled:opacity-60 disabled:cursor-not-allowed text-white px-4 py-2 rounded-lg text-sm transition-colors"
            >
              {isImporting ? '导入中...' : '确认导入'}
            </button>
          </div>
        </div>
      )}

      {/* Words List */}
      <div className="bg-slate-900/50 border border-slate-800 rounded-2xl overflow-hidden mt-8">
        {words?.length === 0 ? (
          <div className="py-12 text-center text-slate-500">
            <Upload size={48} className="mx-auto mb-4 opacity-20" />
            <p>这个文件夹空空如也，快导入些单词吧！</p>
          </div>
        ) : (
          <div className="divide-y divide-slate-800/50 max-h-[60vh] overflow-y-auto custom-scrollbar">
            {words?.map((word) => (
              <div key={word.id} className="p-4 flex items-center justify-between hover:bg-slate-800/30 transition-colors group">
                {editingId === word.id ? (
                  <div className="flex-1 flex flex-col sm:flex-row gap-2 mr-4">
                    <input
                      value={editForm.english}
                      onChange={(e) => setEditForm(prev => ({ ...prev, english: e.target.value }))}
                      className="flex-1 bg-slate-950 border border-slate-700 rounded-lg px-3 py-1.5 text-sm focus:border-blue-500 outline-none"
                    />
                    <input
                      value={editForm.chinese}
                      onChange={(e) => setEditForm(prev => ({ ...prev, chinese: e.target.value }))}
                      className="flex-1 bg-slate-950 border border-slate-700 rounded-lg px-3 py-1.5 text-sm focus:border-blue-500 outline-none"
                    />
                  </div>
                ) : (
                  <div className="flex-1 grid grid-cols-2 gap-4">
                    <span className="font-medium text-slate-200">{word.english}</span>
                    <span className="text-slate-400">{word.chinese}</span>
                  </div>
                )}

                <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  {editingId === word.id ? (
                    <>
                      <button onClick={saveEdit} className="p-1.5 text-emerald-400 hover:bg-emerald-500/20 rounded-lg transition-colors"><Save size={16} /></button>
                      <button onClick={() => setEditingId(null)} className="p-1.5 text-slate-400 hover:bg-slate-700 rounded-lg transition-colors"><X size={16} /></button>
                    </>
                  ) : (
                    <>
                      <button onClick={() => startEdit(word)} className="p-1.5 text-blue-400 hover:bg-blue-500/20 rounded-lg transition-colors"><Edit2 size={16} /></button>
                      <button onClick={() => handleDelete(word.id)} className="p-1.5 text-rose-400 hover:bg-rose-500/20 rounded-lg transition-colors"><Trash2 size={16} /></button>
                    </>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
