import { useLiveQuery } from 'dexie-react-hooks';
import { db } from '../lib/db';
import { BookOpen, Brain, PlayCircle, Folder, type LucideIcon } from 'lucide-react';
import { Link } from 'react-router-dom';
import { useEffect, useRef } from 'react';

// Word Sphere Component
function WordSphere({ words }: { words: { english: string; chinese: string }[] }) {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current || words.length === 0) return;

    const container = containerRef.current;
    const items = container.children;
    const radius = Math.min(container.offsetWidth, container.offsetHeight) / 2 - 20;

    let mouseX = 0;
    let mouseY = 0;
    let active = false;

    // Distribute words on a sphere using Fibonacci spiral
    const phi = Math.PI * (3 - Math.sqrt(5));
    
    Array.from(items).forEach((item, i) => {
      const el = item as HTMLElement;
      const y = 1 - (i / (items.length - 1)) * 2; 
      const radiusAtY = Math.sqrt(1 - y * y);
      const theta = phi * i;

      const x = Math.cos(theta) * radiusAtY;
      const z = Math.sin(theta) * radiusAtY;

      // Store initial 3D coordinates
      el.dataset.x = String(x * radius);
      el.dataset.y = String(y * radius);
      el.dataset.z = String(z * radius);
      
      // Add random pastel color
      const hue = Math.floor(Math.random() * 360);
      el.style.color = `hsl(${hue}, 70%, 70%)`;
    });

    const updatePositions = () => {
      // Auto rotation base speed + mouse influence
      const rotX = (mouseY * 0.0001) + 0.003;
      const rotY = (mouseX * 0.0001) + 0.003;

      const sinX = Math.sin(rotX);
      const cosX = Math.cos(rotX);
      const sinY = Math.sin(rotY);
      const cosY = Math.cos(rotY);

      Array.from(items).forEach(item => {
        const el = item as HTMLElement;
        let x = parseFloat(el.dataset.x!);
        let y = parseFloat(el.dataset.y!);
        let z = parseFloat(el.dataset.z!);

        // Rotate around X axis
        const y1 = y * cosX - z * sinX;
        const z1 = z * cosX + y * sinX;

        // Rotate around Y axis
        const x2 = x * cosY - z1 * sinY;
        const z2 = z1 * cosY + x * sinY;

        // Update stored coordinates
        el.dataset.x = String(x2);
        el.dataset.y = String(y1);
        el.dataset.z = String(z2);

        // Calculate 2D projection with more perspective distance to keep the sphere smaller
        const scale = 250 / (350 + z2);
        const x3d = x2 * scale;
        const y3d = y1 * scale;

        // Apply styles
        el.style.transform = `translate3d(${x3d}px, ${y3d}px, ${z2}px) scale(${scale})`;
        el.style.opacity = String(Math.max(0.1, (scale - 0.4) * 2.5));
        el.style.zIndex = String(Math.floor(scale * 100));
        
        // Add slight blur for depth effect
        const blur = Math.max(0, (1 - scale) * 4);
        el.style.filter = `blur(${blur}px)`;
      });

      if (active) requestAnimationFrame(updatePositions);
    };

    const handleMouseMove = (e: MouseEvent) => {
      const rect = container.getBoundingClientRect();
      mouseX = e.clientX - rect.left - rect.width / 2;
      mouseY = e.clientY - rect.top - rect.height / 2;
    };

    container.addEventListener('mousemove', handleMouseMove);
    container.addEventListener('mouseleave', () => { mouseX = 0; mouseY = 0; });
    
    active = true;
    updatePositions();

    return () => {
      active = false;
      container.removeEventListener('mousemove', handleMouseMove);
      container.removeEventListener('mouseleave', () => { mouseX = 0; mouseY = 0; });
    };
  }, [words]);

  if (words.length === 0) {
    return (
      <div className="h-[300px] flex flex-col items-center justify-center border border-dashed border-slate-700 rounded-3xl bg-slate-900/50 group hover:border-blue-500/50 transition-colors">
        <Folder size={48} className="text-slate-600 mb-4 group-hover:text-blue-400 transition-colors" />
        <p className="text-slate-400 mb-4">你的词库还是空的</p>
        <Link 
          to="/library" 
          className="px-6 py-2 bg-blue-600/20 text-blue-400 rounded-full hover:bg-blue-600 hover:text-white transition-all shadow-[0_0_20px_rgba(37,99,235,0.2)]"
        >
          去添加单词
        </Link>
      </div>
    );
  }

  // Limit words for performance
  const displayWords = words.slice(0, 40);

  return (
    <div className="relative h-[300px] md:h-[400px] w-full overflow-hidden rounded-3xl bg-slate-950 border border-slate-800 flex items-center justify-center [perspective:1200px]">
      <div className="absolute inset-0 bg-gradient-to-b from-blue-500/5 to-purple-500/5 pointer-events-none" />
      <div 
        ref={containerRef} 
        className="relative w-full h-full flex items-center justify-center [transform-style:preserve-3d] scale-75 md:scale-90"
      >
        {displayWords.map((word, i) => (
          <div 
            key={i}
            className="absolute whitespace-nowrap text-center font-medium select-none pointer-events-none will-change-transform"
            style={{ 
              textShadow: '0 2px 10px rgba(0,0,0,0.8)'
            }}
          >
            <div className="text-lg md:text-xl font-bold">{word.english}</div>
            <div className="text-xs md:text-sm opacity-80">{word.chinese}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default function Dashboard() {
  const foldersCount = useLiveQuery(() => db.folders.count()) || 0;
  const wordsCount = useLiveQuery(() => db.words.count()) || 0;
  const mistakesCount = useLiveQuery(() => db.words.where('mistakeCount').above(0).count()) || 0;
  
  // Get words for the sphere
  const allWords = useLiveQuery(() => db.words.toArray()) || [];

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <header className="space-y-4">
        <h1 className="text-3xl font-bold tracking-tight">LingoFlow 词库</h1>
        <WordSphere words={allWords} />
      </header>

      {/* Stats Grid */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <StatCard icon={Folder} label="文件夹" value={foldersCount} color="blue" />
        <StatCard icon={BookOpen} label="总单词数" value={wordsCount} color="emerald" />
        <StatCard icon={Brain} label="待特训错题" value={mistakesCount} color="rose" />
      </div>

      {/* Quick Actions */}
      <section className="space-y-4">
        <h2 className="text-xl font-semibold flex items-center gap-2">
          <PlayCircle className="text-blue-500" />
          快捷入口
        </h2>
        <div className="grid md:grid-cols-2 gap-4">
          <Link
            to="/library"
            className="group relative overflow-hidden rounded-2xl p-6 bg-gradient-to-br from-slate-800 to-slate-900 border border-slate-700 hover:border-blue-500/50 transition-all duration-300"
          >
            <div className="absolute inset-0 bg-blue-500/10 opacity-0 group-hover:opacity-100 transition-opacity" />
            <div className="relative z-10 space-y-4">
              <div className="p-3 bg-blue-500/20 w-fit rounded-xl">
                <BookOpen className="text-blue-400" size={28} />
              </div>
              <div>
                <h3 className="text-xl font-semibold mb-1 text-slate-100">管理词库</h3>
                <p className="text-sm text-slate-400">导入新单词，创建文件夹，整理你的学习资料。</p>
              </div>
            </div>
          </Link>

          <Link
            to="/mistakes"
            className="group relative overflow-hidden rounded-2xl p-6 bg-gradient-to-br from-slate-800 to-slate-900 border border-slate-700 hover:border-rose-500/50 transition-all duration-300"
          >
            <div className="absolute inset-0 bg-rose-500/10 opacity-0 group-hover:opacity-100 transition-opacity" />
            <div className="relative z-10 space-y-4">
              <div className="p-3 bg-rose-500/20 w-fit rounded-xl">
                <Brain className="text-rose-400" size={28} />
              </div>
              <div>
                <h3 className="text-xl font-semibold mb-1 text-slate-100">错题特训</h3>
                <p className="text-sm text-slate-400">针对易错词进行沉浸式默写，攻克难关。</p>
              </div>
            </div>
          </Link>
        </div>
      </section>
    </div>
  );
}

function StatCard({
  icon: Icon,
  label,
  value,
  color,
}: {
  icon: LucideIcon;
  label: string;
  value: number;
  color: 'blue' | 'emerald' | 'rose';
}) {
  const colors = {
    blue: 'text-blue-400 bg-blue-500/10',
    emerald: 'text-emerald-400 bg-emerald-500/10',
    rose: 'text-rose-400 bg-rose-500/10',
  };

  return (
    <div className="rounded-2xl p-4 bg-slate-800/50 border border-slate-700/50 flex flex-col items-center justify-center space-y-2">
      <div className={`p-2 rounded-lg ${colors[color as keyof typeof colors]}`}>
        <Icon size={24} />
      </div>
      <div className="text-2xl font-bold">{value}</div>
      <div className="text-xs text-slate-400 font-medium">{label}</div>
    </div>
  );
}
