import { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useLiveQuery } from 'dexie-react-hooks';
import { db } from '../lib/db';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronLeft, Trophy, RefreshCcw } from 'lucide-react';
import { cn } from '../utils/cn';

interface Card {
  id: string;
  wordId: string;
  content: string;
  type: 'english' | 'chinese';
  matched: boolean;
  matchColorClass?: string; // Add color class for matched cards
}

const MATCH_COLORS = [
  'bg-rose-500/20 border-rose-500/50 text-rose-300',
  'bg-emerald-500/20 border-emerald-500/50 text-emerald-300',
  'bg-amber-500/20 border-amber-500/50 text-amber-300',
  'bg-fuchsia-500/20 border-fuchsia-500/50 text-fuchsia-300',
  'bg-cyan-500/20 border-cyan-500/50 text-cyan-300',
  'bg-indigo-500/20 border-indigo-500/50 text-indigo-300',
  'bg-lime-500/20 border-lime-500/50 text-lime-300',
  'bg-orange-500/20 border-orange-500/50 text-orange-300',
];

export default function MatchStudy() {
  const { folderId } = useParams<{ folderId: string }>();
  const navigate = useNavigate();
  const words = useLiveQuery(() => folderId ? db.words.where('folderId').equals(folderId).toArray() : [], [folderId]);

  const [leftCards, setLeftCards] = useState<Card[]>([]);
  const [rightCards, setRightCards] = useState<Card[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [score, setScore] = useState(0);
  const [isFinished, setIsFinished] = useState(false);

  const initGame = useCallback(() => {
    if (!words) return;
    
    // Pick up to 8 random words
    const shuffledWords = [...words].sort(() => Math.random() - 0.5).slice(0, 8);
    
    const engCards: Card[] = shuffledWords.map((w, index) => ({ 
      id: Math.random().toString(), wordId: w.id, content: w.english, type: 'english', matched: false, matchColorClass: MATCH_COLORS[index % MATCH_COLORS.length]
    }));
    
    const chiCards: Card[] = shuffledWords.map((w, index) => ({ 
      id: Math.random().toString(), wordId: w.id, content: w.chinese, type: 'chinese', matched: false, matchColorClass: MATCH_COLORS[index % MATCH_COLORS.length]
    }));

    setLeftCards(engCards.sort(() => Math.random() - 0.5));
    setRightCards(chiCards.sort(() => Math.random() - 0.5));
    setScore(0);
    setIsFinished(false);
    setSelectedId(null);
  }, [words]);

  useEffect(() => {
    if (words && words.length > 0) {
      initGame();
    }
  }, [initGame, words]);

  const handleCardClick = (card: Card) => {
    if (card.matched || selectedId === card.id) return;

    if (!selectedId) {
      setSelectedId(card.id);
      return;
    }

    const selected = leftCards.find(c => c.id === selectedId) || rightCards.find(c => c.id === selectedId);
    if (!selected) return;

    // Check match
    if (selected.wordId === card.wordId && selected.type !== card.type) {
      // Match found
      setLeftCards(prev => prev.map(c => 
        (c.id === card.id || c.id === selectedId) ? { ...c, matched: true } : c
      ));
      setRightCards(prev => prev.map(c => 
        (c.id === card.id || c.id === selectedId) ? { ...c, matched: true } : c
      ));
      setScore(s => s + 10);
      
      // Check if finished
      const unmatchedLeft = leftCards.filter(c => !c.matched);
      const unmatchedRight = rightCards.filter(c => !c.matched);
      // Because we just matched 2 cards (1 left, 1 right), the next unmatched count would be 1 less each side
      if (unmatchedLeft.length <= 1 && unmatchedRight.length <= 1) {
        setIsFinished(true);
      }
    } else {
      // No match, deduct score slightly
      setScore(s => Math.max(0, s - 2));
    }
    
    setSelectedId(null);
  };

  if (!words) return <div className="text-center py-20">加载中...</div>;
  if (words.length < 4) return (
    <div className="text-center py-20 space-y-4">
      <p className="text-slate-400">单词数量不足，至少需要4个单词才能开始连连看。</p>
      <button onClick={() => navigate(-1)} className="text-blue-500 hover:underline">返回</button>
    </div>
  );

  return (
    <div className="flex flex-col h-full animate-in fade-in duration-500">
      <header className="flex justify-between items-center mb-8 shrink-0">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-400 hover:text-white transition-colors">
          <ChevronLeft size={20} />
          <span>返回</span>
        </button>
        <div className="flex items-center gap-4">
          <div className="bg-slate-800/50 px-4 py-2 rounded-xl flex items-center gap-2 font-mono text-lg text-emerald-400 border border-slate-700/50">
            <Trophy size={20} className="text-yellow-500" />
            {score}
          </div>
          <button onClick={initGame} className="p-2 text-slate-400 hover:text-blue-400 hover:bg-blue-500/10 rounded-lg transition-colors">
            <RefreshCcw size={20} />
          </button>
        </div>
      </header>

      <div className="flex-1 flex flex-col items-center justify-center relative">
        {isFinished ? (
          <motion.div 
            initial={{ scale: 0.8, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            className="text-center space-y-6 p-8 bg-slate-800/50 border border-slate-700 rounded-3xl backdrop-blur-sm"
          >
            <Trophy size={64} className="mx-auto text-yellow-500 animate-bounce" />
            <div>
              <h2 className="text-3xl font-bold text-slate-100 mb-2">挑战完成！</h2>
              <p className="text-slate-400">最终得分: <span className="text-emerald-400 font-mono font-bold text-xl">{score}</span></p>
            </div>
            <div className="flex gap-4 justify-center">
              <button onClick={() => navigate(-1)} className="px-6 py-3 rounded-xl border border-slate-600 hover:bg-slate-700 transition-colors">返回</button>
              <button onClick={initGame} className="px-6 py-3 rounded-xl bg-blue-600 hover:bg-blue-500 text-white font-medium transition-colors shadow-lg shadow-blue-500/20">再来一局</button>
            </div>
          </motion.div>
        ) : (
          <div className="grid grid-cols-2 gap-4 w-full max-w-4xl px-2 sm:px-4 pb-20">
            {/* Left Column - English */}
            <div className="flex flex-col gap-3">
              <AnimatePresence>
                {leftCards.map(card => (
                  <motion.button
                    key={card.id}
                    layout
                    initial={{ scale: 0.8, opacity: 0 }}
                    animate={{ 
                      scale: 1, 
                      opacity: 1,
                      rotateY: selectedId === card.id ? 10 : 0
                    }}
                    whileHover={!card.matched ? { scale: 1.02 } : {}}
                    whileTap={!card.matched ? { scale: 0.98 } : {}}
                    onClick={() => handleCardClick(card)}
                    disabled={card.matched}
                    className={cn(
                      "w-full rounded-xl flex items-center justify-center p-4 min-h-[4rem] sm:min-h-[5rem] text-center cursor-pointer transition-all duration-300 shadow-sm border",
                      card.matched 
                        ? cn(card.matchColorClass, "pointer-events-none") 
                        : selectedId === card.id 
                          ? "bg-blue-600/20 border-blue-500 text-blue-100 shadow-blue-500/20 shadow-lg ring-2 ring-blue-500/50" 
                          : "bg-slate-800 border-slate-700 hover:border-slate-500 text-slate-200"
                    )}
                  >
                    <span className="font-medium text-lg sm:text-xl font-sans">
                      {card.content}
                    </span>
                  </motion.button>
                ))}
              </AnimatePresence>
            </div>

            {/* Right Column - Chinese */}
            <div className="flex flex-col gap-3">
              <AnimatePresence>
                {rightCards.map(card => (
                  <motion.button
                    key={card.id}
                    layout
                    initial={{ scale: 0.8, opacity: 0 }}
                    animate={{ 
                      scale: 1, 
                      opacity: 1,
                      rotateY: selectedId === card.id ? 10 : 0
                    }}
                    whileHover={!card.matched ? { scale: 1.02 } : {}}
                    whileTap={!card.matched ? { scale: 0.98 } : {}}
                    onClick={() => handleCardClick(card)}
                    disabled={card.matched}
                    className={cn(
                      "w-full rounded-xl flex items-center justify-center p-4 min-h-[4rem] sm:min-h-[5rem] text-center cursor-pointer transition-all duration-300 shadow-sm border",
                      card.matched 
                        ? cn(card.matchColorClass, "pointer-events-none") 
                        : selectedId === card.id 
                          ? "bg-blue-600/20 border-blue-500 text-blue-100 shadow-blue-500/20 shadow-lg ring-2 ring-blue-500/50" 
                          : "bg-slate-800 border-slate-700 hover:border-slate-500 text-slate-200"
                    )}
                  >
                    <span className="font-medium text-base sm:text-lg">
                      {card.content}
                    </span>
                  </motion.button>
                ))}
              </AnimatePresence>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
