import Dexie, { Table } from 'dexie';

export interface Folder {
  id: string;
  name: string;
  createdAt: number;
}

export interface Word {
  id: string;
  folderId: string;
  english: string;
  chinese: string;
  mistakeCount: number;
  lastPracticed?: number;
  createdAt: number;
  phonetic?: string;
  exampleSentence?: string;
}

export class AppDatabase extends Dexie {
  folders!: Table<Folder, string>;
  words!: Table<Word, string>;

  constructor() {
    super('LanguageLearningAppDB');
    this.version(1).stores({
      folders: 'id, name, createdAt',
      words: 'id, folderId, english, chinese, mistakeCount, lastPracticed',
    });
    this.version(2).stores({
      folders: 'id, name, createdAt',
      words: 'id, folderId, english, chinese, mistakeCount, lastPracticed, createdAt',
    }).upgrade(trans => {
      return trans.table('words').toCollection().modify(word => {
        word.createdAt = Date.now();
      });
    });
    this.version(3).stores({
      folders: 'id, name, createdAt',
      words: 'id, folderId, english, chinese, mistakeCount, lastPracticed, createdAt, phonetic',
    });
    this.version(4).stores({
      folders: 'id, name, createdAt',
      words: 'id, folderId, english, chinese, mistakeCount, lastPracticed, createdAt, phonetic, exampleSentence',
    });
  }
}

export const db = new AppDatabase();
