import { useState, useMemo } from 'react';
import { useLiveQuery } from 'dexie-react-hooks';
import { db } from '../lib/db';
import { Link } from 'react-router-dom';
import { Plus, Folder, Trash2, ArrowRight, Edit2, Check, X } from 'lucide-react';
import { generateId } from '../utils/cn';

export default function Library() {
  const folders = useLiveQuery(() => db.folders.toArray());
  const [newFolderName, setNewFolderName] = useState('');
  const [editingFolderId, setEditingFolderId] = useState<string | null>(null);
  const [editFolderName, setEditFolderName] = useState('');

  const sortedFolders = useMemo(() => {
    if (!folders) return [];
    return [...folders].sort((a, b) => b.createdAt - a.createdAt);
  }, [folders]);

  const handleCreateFolder = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newFolderName.trim()) return;

    await db.folders.add({
      id: generateId(),
      name: newFolderName.trim(),
      createdAt: Date.now(),
    });
    setNewFolderName('');
  };

  const handleDelete = async (id: string, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (confirm('确定要删除此文件夹及其中的所有单词吗？')) {
      await db.words.where('folderId').equals(id).delete();
      await db.folders.delete(id);
    }
  };

  const handleRenameFolder = async (id: string, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (!editFolderName.trim()) return;
    
    await db.folders.update(id, { name: editFolderName.trim() });
    setEditingFolderId(null);
  };

  const startEditing = (folder: any, e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setEditingFolderId(folder.id);
    setEditFolderName(folder.name);
  };

  const cancelEditing = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setEditingFolderId(null);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <header className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-slate-100">单词库管理</h1>
          <p className="text-slate-400 text-sm mt-1">创建文件夹来分类你的单词。</p>
        </div>
      </header>

      {/* Create Folder Form */}
      <form onSubmit={handleCreateFolder} className="flex gap-2">
        <input
          type="text"
          value={newFolderName}
          onChange={(e) => setNewFolderName(e.target.value)}
          placeholder="输入新文件夹名称..."
          className="flex-1 bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 text-slate-100 focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition-all"
        />
        <button
          type="submit"
          disabled={!newFolderName.trim()}
          className="bg-blue-600 hover:bg-blue-500 disabled:opacity-50 disabled:cursor-not-allowed text-white px-6 py-3 rounded-xl font-medium transition-all flex items-center gap-2"
        >
          <Plus size={20} />
          <span className="hidden sm:inline">新建</span>
        </button>
      </form>

      {/* Folders Grid */}
      <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4 mt-8">
        {sortedFolders.map((folder) => (
          <Link
            key={folder.id}
            to={`/library/${folder.id}`}
            className="group relative bg-slate-800/50 border border-slate-700 hover:border-blue-500/50 rounded-2xl p-5 transition-all duration-300 hover:-translate-y-1 hover:shadow-xl hover:shadow-blue-500/10 flex flex-col justify-between"
          >
            <div className="flex justify-between items-start mb-4">
              <div className="p-3 bg-blue-500/10 text-blue-400 rounded-xl group-hover:scale-110 transition-transform">
                <Folder size={24} />
              </div>
              <div className="flex items-center opacity-0 group-hover:opacity-100 transition-opacity">
                {editingFolderId === folder.id ? (
                  <>
                    <button
                      onClick={(e) => handleRenameFolder(folder.id, e)}
                      className="text-emerald-500 hover:text-emerald-400 p-2 hover:bg-emerald-500/10 rounded-lg transition-colors"
                    >
                      <Check size={18} />
                    </button>
                    <button
                      onClick={cancelEditing}
                      className="text-slate-400 hover:text-slate-300 p-2 hover:bg-slate-700 rounded-lg transition-colors"
                    >
                      <X size={18} />
                    </button>
                  </>
                ) : (
                  <>
                    <button
                      onClick={(e) => startEditing(folder, e)}
                      className="text-slate-400 hover:text-blue-400 p-2 hover:bg-blue-500/10 rounded-lg transition-colors"
                    >
                      <Edit2 size={18} />
                    </button>
                    <button
                      onClick={(e) => handleDelete(folder.id, e)}
                      className="text-slate-400 hover:text-rose-500 p-2 hover:bg-rose-500/10 rounded-lg transition-colors"
                    >
                      <Trash2 size={18} />
                    </button>
                  </>
                )}
              </div>
            </div>
            
            <div>
              {editingFolderId === folder.id ? (
                <input
                  autoFocus
                  type="text"
                  value={editFolderName}
                  onChange={(e) => setEditFolderName(e.target.value)}
                  onClick={(e) => e.preventDefault()}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter') {
                      handleRenameFolder(folder.id, e as any);
                    } else if (e.key === 'Escape') {
                      cancelEditing(e as any);
                    }
                  }}
                  className="w-full bg-slate-950 border border-slate-700 rounded-lg px-2 py-1 text-slate-100 focus:outline-none focus:border-blue-500 mb-1"
                />
              ) : (
                <h3 className="text-lg font-semibold text-slate-200 mb-1">{folder.name}</h3>
              )}
              <div className="flex items-center justify-between text-sm text-slate-500">
                <span>{new Date(folder.createdAt).toLocaleDateString()}</span>
                <ArrowRight size={16} className="opacity-0 group-hover:opacity-100 -translate-x-2 group-hover:translate-x-0 transition-all" />
              </div>
            </div>
          </Link>
        ))}
        {folders?.length === 0 && (
          <div className="col-span-full py-12 text-center text-slate-500 bg-slate-900/50 rounded-2xl border border-dashed border-slate-700">
            <Folder size={48} className="mx-auto mb-4 opacity-50" />
            <p>暂无文件夹，赶快创建一个吧！</p>
          </div>
        )}
      </div>
    </div>
  );
}
