import { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { useLiveQuery } from 'dexie-react-hooks';
import { db, Word } from '../lib/db';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronLeft, Flag, CheckCircle2, AlertCircle, Settings2, Eye, EyeOff, Volume2, Lightbulb, ArrowRight, ArrowLeft } from 'lucide-react';
import { cn } from '../utils/cn';
import confetti from 'canvas-confetti';

export default function DictationStudy() {
  const { folderId } = useParams<{ folderId: string }>();
  const location = useLocation();
  const isMistakesMode = location.pathname.includes('/study/mistakes');
  const navigate = useNavigate();
  
  const allWords = useLiveQuery(() => {
    if (isMistakesMode) {
      return db.words.where('mistakeCount').above(0).toArray();
    }
    return folderId ? db.words.where('folderId').equals(folderId).toArray() : [];
  }, [folderId, isMistakesMode]);

  const [queue, setQueue] = useState<Word[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [input, setInput] = useState('');
  const [errorIndex, setErrorIndex] = useState<number | null>(null);
  const [consecutiveErrors, setConsecutiveErrors] = useState(0);
  const [showBackgroundHint, setShowBackgroundHint] = useState(false);
  const [isFinished, setIsFinished] = useState(false);
  
  // Settings
  const [errorThreshold, setErrorThreshold] = useState(2); // Threshold to show hint
  const [showSettings, setShowSettings] = useState(false);
  const [phonetic, setPhonetic] = useState<string>('');
  const [exampleSentence, setExampleSentence] = useState<string>('');
  const [showExample, setShowExample] = useState(false);
  const [isCurrentWordCompleted, setIsCurrentWordCompleted] = useState(false);
  const [autoNext, setAutoNext] = useState(true); // Settings: auto go to next word

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (allWords && allWords.length > 0 && queue.length === 0 && !isFinished) {
      // Shuffle words for study
      setQueue([...allWords].sort(() => Math.random() - 0.5));
    }
  }, [allWords, isFinished, queue.length]);

  const currentWord = queue[currentIndex];

  useEffect(() => {
    if (inputRef.current && !isCurrentWordCompleted) {
      inputRef.current.focus();
    }
    
    if (currentWord && !isFinished) {
      // Stop previous speech if any
      window.speechSynthesis.cancel();
      
      // Auto play speech
      const utterance = new SpeechSynthesisUtterance(currentWord.english);
      utterance.lang = 'en-US';
      window.speechSynthesis.speak(utterance);

      // Fetch phonetic and example if not cached
      if (currentWord.phonetic !== undefined && currentWord.exampleSentence !== undefined) {
        setPhonetic(currentWord.phonetic);
        setExampleSentence(currentWord.exampleSentence);
      } else {
        let isMounted = true;
        setPhonetic('');
        setExampleSentence('');
        
        fetch(`https://api.dictionaryapi.dev/api/v2/entries/en/${encodeURIComponent(currentWord.english)}`)
          .then(res => res.json())
          .then(async data => {
            if (isMounted && Array.isArray(data) && data.length > 0) {
              // Find the first valid phonetic text
              const ph = data[0].phonetic || data[0].phonetics?.find((p: any) => p.text)?.text || '';
              
              // Find the first example sentence
              let ex = '';
              for (const meaning of data[0].meanings || []) {
                for (const def of meaning.definitions || []) {
                  if (def.example) {
                    ex = def.example;
                    break;
                  }
                }
                if (ex) break;
              }

              setPhonetic(ph);
              setExampleSentence(ex);
              // Cache it to database
              await db.words.update(currentWord.id, { phonetic: ph, exampleSentence: ex });
            } else if (isMounted) {
              // Not found, cache empty string so we don't refetch
              await db.words.update(currentWord.id, { phonetic: '', exampleSentence: '' });
            }
          })
          .catch(() => {
            // Ignore errors
          });

        return () => {
          isMounted = false;
        };
      }
    }
  }, [currentIndex, isFinished, currentWord]);

  const handleInputChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (isFinished || !currentWord || isCurrentWordCompleted) return;
    
    const val = e.target.value.toLowerCase();
    const target = currentWord.english.toLowerCase();
    
    // Check letter by letter
    let isError = false;
    for (let i = 0; i < val.length; i++) {
      if (val[i] !== target[i]) {
        isError = true;
        setErrorIndex(i);
        break;
      }
    }

    if (isError) {
      // Vibrate if supported
      if (navigator.vibrate) navigator.vibrate(50);
      
      setConsecutiveErrors(prev => prev + 1);

      // Mark as mistake
      await db.words.update(currentWord.id, { 
        mistakeCount: (currentWord.mistakeCount || 0) + 1,
        lastPracticed: Date.now()
      });
      
      return; // Do not update input if error
    }

    // No error
    setErrorIndex(null);
    setConsecutiveErrors(0);
    setInput(val);

    // Check if fully correct
    if (val === target) {
      setIsCurrentWordCompleted(true);
      confetti({
        particleCount: 100,
        spread: 70,
        origin: { y: 0.6 },
        colors: ['#34d399', '#3b82f6', '#60a5fa']
      });

      if (autoNext) {
        setTimeout(() => {
          handleNextWord();
        }, 1000); // give time for the surprise animation
      } else {
        // Not auto-next: stay on word, show example sentence if available
        if (exampleSentence) {
          setShowExample(true);
        }
      }
    }
  };

  const handleNextWord = async () => {
    if (!currentWord) return;
    
    // Update last practiced
    await db.words.update(currentWord.id, { lastPracticed: Date.now() });

    if (currentIndex < queue.length - 1) {
      setCurrentIndex(prev => prev + 1);
      setInput('');
      setErrorIndex(null);
      setConsecutiveErrors(0);
      setShowExample(false);
      setIsCurrentWordCompleted(false);
    } else {
      setIsFinished(true);
    }
  };

  const handlePrevWord = () => {
    if (currentIndex > 0) {
      setCurrentIndex(prev => prev - 1);
      setInput(queue[currentIndex - 1].english); // Prefill if going back
      setErrorIndex(null);
      setConsecutiveErrors(0);
      setShowExample(false);
      setIsCurrentWordCompleted(true);
    }
  };

  const handleSkip = async () => {
    if (!currentWord) return;
    await db.words.update(currentWord.id, { 
      mistakeCount: (currentWord.mistakeCount || 0) + 1,
      lastPracticed: Date.now()
    });
    handleNextWord();
  };

  // Listen for Enter key to go to next word if completed and autoNext is off
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Enter' && isCurrentWordCompleted && !isFinished) {
        e.preventDefault();
        handleNextWord();
      }
    };
    
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isCurrentWordCompleted, isFinished, currentIndex, queue.length]);

  if (!allWords) return <div className="text-center py-20 text-slate-400">加载中...</div>;
  if (allWords.length === 0) return (
    <div className="text-center py-20 space-y-4">
      <p className="text-slate-400">{isMistakesMode ? '太棒了，没有需要特训的错题！' : '该文件夹暂无单词，请先导入。'}</p>
      <button onClick={() => navigate(-1)} className="text-blue-500 hover:underline">返回</button>
    </div>
  );

  return (
    <div className="flex flex-col h-[calc(100vh-100px)] animate-in fade-in duration-500 pb-safe">
      <header className="flex justify-between items-center mb-8 shrink-0">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-400 hover:text-white transition-colors">
          <ChevronLeft size={20} /> 返回
        </button>
        <div className="text-sm font-medium text-slate-500">
          {currentIndex + 1} / {queue.length}
        </div>
        <div className="flex items-center gap-4">
          <button 
            onClick={() => setShowBackgroundHint(!showBackgroundHint)} 
            className={cn("flex items-center transition-colors", showBackgroundHint ? "text-emerald-400" : "text-slate-400 hover:text-slate-300")} 
            title={showBackgroundHint ? "关闭背景提示" : "开启背景答案模式"}
          >
            {showBackgroundHint ? <Eye size={20} /> : <EyeOff size={20} />}
          </button>
          <button 
            onClick={() => setShowSettings(!showSettings)} 
            className={cn("flex items-center transition-colors", showSettings ? "text-blue-400" : "text-slate-400 hover:text-slate-300")} 
            title="设置"
          >
            <Settings2 size={20} />
          </button>
          <button onClick={handleSkip} className="flex items-center text-slate-400 hover:text-rose-400 transition-colors" title="跳过（记为错误）">
            <Flag size={20} />
          </button>
        </div>
      </header>

      {/* Settings Panel */}
      <AnimatePresence>
        {showSettings && (
          <motion.div 
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            className="overflow-hidden bg-slate-800/50 border-b border-slate-800 shrink-0"
          >
            <div className="p-4 max-w-2xl mx-auto flex flex-col gap-4">
              <div className="flex items-center justify-between">
                <div className="text-sm text-slate-300">
                  错误提示阈值（连续输错几次后提示后续字母）：
                </div>
                <div className="flex items-center gap-2">
                  {[1, 2, 3, 5].map(val => (
                    <button
                      key={val}
                      onClick={() => setErrorThreshold(val)}
                      className={cn(
                        "w-8 h-8 rounded-lg flex items-center justify-center text-sm font-medium transition-colors",
                        errorThreshold === val 
                          ? "bg-blue-600 text-white" 
                          : "bg-slate-900 text-slate-400 hover:bg-slate-700 hover:text-slate-200"
                      )}
                    >
                      {val}
                    </button>
                  ))}
                </div>
              </div>
              <div className="flex items-center justify-between">
                <div className="text-sm text-slate-300">
                  自动进入下一个（开启后默写正确自动跳过）：
                </div>
                <button
                  onClick={() => setAutoNext(!autoNext)}
                  className={cn(
                    "relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 focus:ring-offset-slate-900",
                    autoNext ? "bg-blue-600" : "bg-slate-600"
                  )}
                >
                  <span
                    className={cn(
                      "inline-block h-4 w-4 transform rounded-full bg-white transition-transform",
                      autoNext ? "translate-x-6" : "translate-x-1"
                    )}
                  />
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <div className="flex-1 flex flex-col items-center justify-center max-w-2xl mx-auto w-full relative">
        <AnimatePresence mode="wait">
          {isFinished ? (
            <motion.div
              key="finished"
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              className="text-center space-y-6 bg-slate-900/50 p-12 rounded-3xl border border-slate-800"
            >
              <CheckCircle2 size={80} className="mx-auto text-emerald-500" />
              <div>
                <h2 className="text-3xl font-bold text-slate-100 mb-2">训练完成！</h2>
                <p className="text-slate-400">你已完成所有单词的默写练习。</p>
              </div>
              <button 
                onClick={() => navigate(isMistakesMode ? '/mistakes' : `/library/${folderId}`)}
                className="bg-blue-600 hover:bg-blue-500 text-white px-8 py-3 rounded-xl font-medium transition-colors"
              >
                返回列表
              </button>
            </motion.div>
          ) : currentWord && (
            <motion.div
              key={currentWord.id}
              initial={{ x: 20, opacity: 0 }}
              animate={{ x: 0, opacity: 1 }}
              exit={{ x: -20, opacity: 0 }}
              className="w-full text-center space-y-12"
            >
              {/* Chinese Meaning & Phonetic */}
              <div className="space-y-4">
                <div className="text-3xl md:text-5xl font-medium text-slate-200 tracking-wide">
                  {currentWord.chinese}
                </div>
                <div className="flex items-center justify-center gap-3 text-slate-400 h-8">
                  <button 
                    onClick={(e) => {
                      e.preventDefault();
                      window.speechSynthesis.cancel();
                      const utterance = new SpeechSynthesisUtterance(currentWord.english);
                      utterance.lang = 'en-US';
                      window.speechSynthesis.speak(utterance);
                      inputRef.current?.focus();
                    }}
                    className="p-2 hover:text-blue-400 hover:bg-blue-500/10 rounded-full transition-colors flex items-center justify-center"
                    title="播放发音"
                  >
                    <Volume2 size={20} />
                  </button>
                  {phonetic && <span className="font-mono text-lg tracking-wider">{phonetic}</span>}
                </div>
                
                {/* Example Sentence Toggle */}
                {exampleSentence && (
                  <div className="flex flex-col items-center">
                    <button
                      onClick={() => setShowExample(!showExample)}
                      className="text-xs text-slate-500 hover:text-blue-400 flex items-center gap-1.5 transition-colors bg-slate-800/30 hover:bg-slate-800/80 px-3 py-1.5 rounded-full"
                    >
                      <Lightbulb size={14} />
                      {showExample ? '隐藏例句' : '查看例句提示'}
                    </button>
                    <AnimatePresence>
                      {showExample && (
                        <motion.div
                          initial={{ opacity: 0, height: 0, y: -10 }}
                          animate={{ opacity: 1, height: 'auto', y: 0 }}
                          exit={{ opacity: 0, height: 0, y: -10 }}
                          className="overflow-hidden mt-4"
                        >
                          <p className="text-slate-300 italic text-center max-w-lg px-4 border-l-2 border-blue-500/50 py-1">
                            "{exampleSentence}"
                          </p>
                        </motion.div>
                      )}
                    </AnimatePresence>
                  </div>
                )}
              </div>

              {/* Input Area */}
              <div className="relative max-w-md mx-auto">
                <input
                  ref={inputRef}
                  type="text"
                  value={input}
                  onChange={handleInputChange}
                  className="absolute inset-0 w-full h-full opacity-0 cursor-default"
                  autoComplete="off"
                  autoCorrect="off"
                  autoCapitalize="off"
                  spellCheck="false"
                  autoFocus
                />
                
                {/* Visual Feedback overlay */}
                <div className="pointer-events-none flex items-center justify-center pb-4 border-b-2 border-slate-700">
                  <div className="text-4xl md:text-6xl font-mono flex gap-1 md:gap-2">
                    {currentWord.english.split('').map((char, i) => {
                      let color = "text-slate-700/30"; // not typed yet
                      let yOffset = 0;
                      const isCorrectlyTyped = i < input.length;
                      
                      // Condition to show background hint letter:
                      // 1. Explicitly turned on background hint mode
                      // 2. OR User made enough consecutive errors and we want to show the next 2 letters
                      const showHintBecauseOfErrors = consecutiveErrors >= errorThreshold && i >= input.length && i < input.length + 2;
                      const shouldShowLetter = isCorrectlyTyped || showBackgroundHint || showHintBecauseOfErrors;
                      
                      if (isCorrectlyTyped) {
                        color = "text-emerald-400"; // correctly typed
                        yOffset = -5; // slight pop when typed
                      } else if (i === errorIndex) {
                        color = "text-rose-500 bg-rose-500/20 rounded"; // error
                      } else if (shouldShowLetter) {
                        color = showHintBecauseOfErrors ? "text-amber-500/70" : "text-slate-500/50"; // hint color
                      }

                      return (
                        <motion.span 
                          key={i} 
                          className={cn("transition-colors inline-block", color)}
                          animate={i === errorIndex ? { x: [-2, 2, -2, 2, 0] } : { y: yOffset }}
                          transition={{ duration: 0.3 }}
                        >
                          {shouldShowLetter || i === errorIndex ? char : '_'}
                        </motion.span>
                      );
                    })}
                  </div>
                </div>
              </div>

              {/* Hint & Status */}
              <div className="h-12 flex items-center justify-center">
                <AnimatePresence mode="wait">
                  {isCurrentWordCompleted && !autoNext ? (
                    <motion.div
                      key="actions"
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, y: -10 }}
                      className="flex items-center gap-4"
                    >
                      <button
                        onClick={handlePrevWord}
                        disabled={currentIndex === 0}
                        className="flex items-center gap-2 px-4 py-2 rounded-xl bg-slate-800 hover:bg-slate-700 text-slate-300 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                      >
                        <ArrowLeft size={18} /> 上一个
                      </button>
                      <button
                        onClick={handleNextWord}
                        className="flex items-center gap-2 px-6 py-2 rounded-xl bg-blue-600 hover:bg-blue-500 text-white font-medium transition-colors shadow-lg shadow-blue-500/20"
                      >
                        下一个 (Enter) <ArrowRight size={18} />
                      </button>
                    </motion.div>
                  ) : consecutiveErrors >= errorThreshold ? (
                    <motion.div
                      key="hint"
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, y: -10 }}
                      className="flex items-center gap-2 text-amber-400 bg-amber-500/10 px-4 py-2 rounded-lg"
                    >
                      <AlertCircle size={18} />
                      <span>请注意上方给出的字母提示</span>
                    </motion.div>
                  ) : null}
                </AnimatePresence>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
}
