import { HashRouter as Router, Routes, Route } from 'react-router-dom';
import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import Library from './pages/Library';
import FolderDetail from './pages/FolderDetail';
import MatchStudy from './pages/MatchStudy';
import DictationStudy from './pages/DictationStudy';
import Mistakes from './pages/Mistakes';
import { useAppStore } from './store/useAppStore';
import { useEffect } from 'react';

function App() {
  const { theme } = useAppStore();

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
      document.body.style.backgroundColor = '#020617'; // bg-slate-950
    } else {
      document.documentElement.classList.remove('dark');
      document.body.style.backgroundColor = '#f8fafc'; // bg-slate-50
    }
  }, [theme]);

  return (
    <Router>
      <Routes>
        <Route path="/" element={<Layout />}>
          <Route index element={<Dashboard />} />
          <Route path="library" element={<Library />} />
          <Route path="library/:folderId" element={<FolderDetail />} />
          <Route path="study/match/:folderId" element={<MatchStudy />} />
          <Route path="study/dictation/:folderId" element={<DictationStudy />} />
          <Route path="mistakes" element={<Mistakes />} />
          <Route path="study/mistakes" element={<DictationStudy />} />
        </Route>
      </Routes>
    </Router>
  );
}

export default App;
